const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const componentGroupBasePremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const sumItemBasePremiums = (items: Item[]): number => {
  const [components, nonComponents] = [items.filter(isComponent), items.filter((i) => !isComponent(i))];
  const nonComponentTotal = nonComponents.reduce((sum, item) => sum + itemBasePremium(item), 0);
  const componentTotal = [...countByType(components)].reduce(
    (sum, [type, count]) => sum + componentGroupBasePremium(type, count),
    0,
  );
  return nonComponentTotal + componentTotal;
};

